/* ---------- Icônes 3D de marque (tuiles Q1) ---------- */
const TILE_IMG = {
  stocks: "data:image/webp;base64,",
  real_estate: "data:image/webp;base64,",
  crypto: "data:image/webp;base64,",
  saver: "data:image/webp;base64,",
};

function InvestorTile({ kind, label, selected, onClick, delay = 0 }) {
  return (
    <button onClick={onClick} className="fiu" style={{
      animationDelay: `${delay}s`,
      display: "flex", flexDirection: "column", alignItems: "center", gap: 13,
      padding: "24px 10px 22px", borderRadius: R.tile,
      background: selected ? C.cardActive : C.card,
      border: `1px solid ${selected ? C.accent : C.cardBorder}`,
      color: C.text, fontFamily: FONT_BODY, fontSize: 14.5, fontWeight: 700,
      cursor: "pointer", transition: "border-color .15s ease, background .15s ease, transform .12s ease",
    }}
      onMouseDown={(e) => (e.currentTarget.style.transform = "scale(.97)")}
      onMouseUp={(e) => (e.currentTarget.style.transform = "scale(1)")}
      onMouseLeave={(e) => (e.currentTarget.style.transform = "scale(1)")}>
      <img src={TILE_IMG[kind]} alt="" style={{ width: 46, height: 46, objectFit: "contain" }} />
      <span>{label}</span>
    </button>
  );
}

