function Sparkle({ x, y, s = 1, delay = 0 }) {
  return (
    <g transform={`translate(${x},${y}) scale(${s})`} style={{ animation: `twinkle 2.4s ease-in-out ${delay}s infinite` }}>
      <path d="M9 0L10.65 6.35L17 8L10.65 9.65L9 16L7.35 9.65L1 8L7.35 6.35L9 0Z" fill="#F1F1F1"/>
    </g>
  );
}
function StarField() {
  const stars = [
    { x: 10, y: 40, s: 0.8, d: 0 }, { x: 250, y: 18, s: 0.7, d: 0.5 },
    { x: 40, y: 150, s: 0.55, d: 1.1 }, { x: 235, y: 130, s: 1, d: 0.3 },
    { x: 130, y: 8, s: 0.5, d: 1.6 }, { x: 270, y: 75, s: 0.5, d: 0.9 },
    { x: 75, y: 95, s: 0.4, d: 1.9 }, { x: 180, y: 170, s: 0.65, d: 1.3 },
  ];
  return (
    <svg width="290" height="200" viewBox="0 0 290 200" fill="none" style={{ position: "absolute", inset: 0, margin: "auto", pointerEvents: "none" }}>
      {stars.map((st, i) => <Sparkle key={i} x={st.x} y={st.y} s={st.s} delay={st.d} />)}
    </svg>
  );
}

