/* ---------- Count-up ---------- */
function useCountUp(target, run, duration = 1200) {
  const [val, setVal] = useState(0);
  useEffect(() => {
    if (!run) { setVal(0); return; }
    let raf; const start = performance.now();
    const tick = (now) => {
      const t = Math.min(1, (now - start) / duration);
      const eased = 1 - Math.pow(1 - t, 3);
      setVal(target * eased);
      if (t < 1) raf = requestAnimationFrame(tick); else setVal(target);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [run, target, duration]);
  return val;
}
function useCount(from, to, run, duration = 1100) {
  const [val, setVal] = useState(from);
  useEffect(() => {
    if (!run) { setVal(from); return; }
    let raf; const start = performance.now();
    const tick = (now) => {
      const t = Math.min(1, (now - start) / duration);
      const eased = 1 - Math.pow(1 - t, 3);
      setVal(from + (to - from) * eased);
      if (t < 1) raf = requestAnimationFrame(tick); else setVal(to);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [run, from, to, duration]);
  return val;
}
function BigNumber({ value, suffix, run }) {
  const v = useCountUp(value, run);
  return <span>{Math.round(v).toLocaleString("en-US")}{suffix}</span>;
}

/* ---------- Typewriter ---------- */
function Typewriter({ text, speed = 22 }) {
  const [n, setN] = useState(0);
  useEffect(() => {
    setN(0); let i = 0;
    const id = setInterval(() => { i++; setN(i); if (i >= text.length) clearInterval(id); }, speed);
    return () => clearInterval(id);
  }, [text]);
  return <span>{text.slice(0, n)}</span>;
}

/* Titre avec micro-typewriter (sans curseur), hauteur réservée pour éviter le saut */
function TWTitle({ text, size = 24, center, speed = 15 }) {
  const [n, setN] = useState(0);
  useEffect(() => {
    setN(0); let i = 0;
    const id = setInterval(() => { i++; setN(i); if (i >= text.length) clearInterval(id); }, speed);
    return () => clearInterval(id);
  }, [text]);
  const base = { fontFamily: FONT_TITLE, fontWeight: 700, fontSize: size, lineHeight: 1.2, letterSpacing: "-0.01em", color: C.text, textAlign: center ? "center" : "left", margin: 0, whiteSpace: "pre-line" };
  return (
    <div style={{ position: "relative" }}>
      <h1 style={{ ...base, visibility: "hidden" }}>{text}</h1>
      <h1 style={{ ...base, position: "absolute", inset: 0 }}>{text.slice(0, n)}</h1>
    </div>
  );
}

