function GrowthBars2({ play }) {
  // hauteurs exponentielles (1ère barre relevée au niveau de la 2e), rendu "pilules"
  const heights = [0.20, 0.23, 0.31, 0.42, 0.55, 0.74, 1.0];
  const W = 330, H = 200, n = heights.length, gap = 13;
  const bw = (W - gap * (n - 1)) / n, r = bw / 2;
  return (
    <svg width="100%" viewBox={`0 0 ${W} ${H + 10}`} fill="none" xmlns="http://www.w3.org/2000/svg" style={{ display: "block", overflow: "visible" }}>
      <defs>
        <linearGradient id="gb2_fill" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0" stopColor="#9CF3BF" stopOpacity="0.95" />
          <stop offset="0.42" stopColor="#5FD792" stopOpacity="0.42" />
          <stop offset="1" stopColor="#5FD792" stopOpacity="0" />
        </linearGradient>
      </defs>
      {heights.map((h, i) => {
        const x = i * (bw + gap), cx = x + bw / 2;
        const fillTop = H * (1 - h), capCy = fillTop + r;
        const growDur = 0.95, growDelay = i * 0.06, capDelay = growDelay + 0.8;
        return (
          <g key={i}>
            <rect x={x} y="0" width={bw} height={H} rx={r} fill="rgba(229,255,253,0.05)" />
            <rect x={x} y={fillTop} width={bw} height={H - fillTop} rx={r} fill="url(#gb2_fill)"
              style={{ transform: play ? "scaleY(1)" : "scaleY(0)", transformBox: "fill-box", transformOrigin: "bottom", transition: `transform ${growDur}s cubic-bezier(.4,0,.2,1) ${growDelay}s` }} />
            <circle cx={cx} cy={capCy} r={r * 0.92} fill="#9DF7BE"
              style={{ transform: play ? "scale(1)" : "scale(0)", transformBox: "fill-box", transformOrigin: "center", opacity: play ? 1 : 0, transition: `transform .5s cubic-bezier(.34,1.56,.64,1) ${capDelay}s, opacity .3s ease ${capDelay}s` }} />
          </g>
        );
      })}
    </svg>
  );
}

/* ---------- CoinStack (cercles verts qui s'empilent) ---------- */
function CoinStack({ play }) {
  const n = 5, cx = 110, rx = 62, ry = 16, baseY = 156, stepY = 23;
  return (
    <svg width="220" height="210" viewBox="0 0 220 210" fill="none" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <linearGradient id="cs_top" x1="48" y1="0" x2="172" y2="0" gradientUnits="userSpaceOnUse">
          <stop stopColor="#B9FBD3" /><stop offset="1" stopColor="#69EA9B" />
        </linearGradient>
        <linearGradient id="cs_side" x1="0" y1="0" x2="0" y2="1">
          <stop stopColor="#3FB877" /><stop offset="1" stopColor="#1F7A4F" />
        </linearGradient>
      </defs>
      {Array.from({ length: n }).map((_, i) => {
        const y = baseY - i * stepY, d = i * 0.11;
        return (
          <g key={i} style={{ opacity: play ? 1 : 0, transform: play ? "translateY(0)" : "translateY(-24px)", transition: `opacity .35s ease ${d}s, transform .5s cubic-bezier(.34,1.5,.5,1) ${d}s` }}>
            <path d={`M ${cx - rx} ${y} a ${rx} ${ry} 0 0 0 ${2 * rx} 0 l 0 8 a ${rx} ${ry} 0 0 1 ${-2 * rx} 0 Z`} fill="url(#cs_side)" />
            <ellipse cx={cx} cy={y} rx={rx} ry={ry} fill="url(#cs_top)" />
            <ellipse cx={cx - 14} cy={y - 3} rx={20} ry={5} fill="#FFFFFF" opacity="0.32" />
          </g>
        );
      })}
    </svg>
  );
}

/* ---------- RadialGauge (jauge radiale, type screen 23%) ---------- */
function RadialGauge({ value, play }) {
  const v = useCountUp(value, play);
  const size = 230, cx = 115, cy = 124, R = 88;
  const a = (-90 + (v / 100) * 360) * Math.PI / 180;
  const ex = cx + R * Math.cos(a), ey = cy + R * Math.sin(a);
  const large = (v / 100) > 0.5 ? 1 : 0;
  const wedge = v > 0.1 ? `M ${cx} ${cy} L ${cx} ${cy - R} A ${R} ${R} 0 ${large} 1 ${ex.toFixed(2)} ${ey.toFixed(2)} Z` : "";
  const mr = R + 16, mx = cx + mr * Math.cos(a), my = cy + mr * Math.sin(a);
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} fill="none" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <radialGradient id="rg_dark" cx="0.5" cy="0.5" r="0.5">
          <stop stopColor="#1C4A42" /><stop offset="1" stopColor="#0B2722" />
        </radialGradient>
        <linearGradient id="rg_bright" x1="0" y1="0" x2="1" y2="1">
          <stop stopColor="#B9FBD3" /><stop offset="1" stopColor="#2FA56C" />
        </linearGradient>
      </defs>
      <circle cx={cx} cy={cy} r={R} fill="url(#rg_dark)" stroke="rgba(255,255,255,0.05)" strokeWidth="1" />
      {wedge && <path d={wedge} fill="url(#rg_bright)" />}
      <line x1={ex.toFixed(2)} y1={ey.toFixed(2)} x2={mx.toFixed(2)} y2={my.toFixed(2)} stroke="white" strokeWidth="1.4" opacity="0.8" />
      <circle cx={ex.toFixed(2)} cy={ey.toFixed(2)} r="4" fill="white" />
      <text x={mx.toFixed(2)} y={(my - 8).toFixed(2)} textAnchor="middle" style={{ fontFamily: FONT_TITLE, fontWeight: 700, fontSize: 19, fill: C.text }}>{Math.round(v)}%</text>
    </svg>
  );
}

